            type       = $type
            scope      = $scope
            message    = $msg
            isBreaking = $isBreaking
        }
    }
    else {
        # If it doesn't match conventional commit format, treat as chore
        return [PSCustomObject]@{
            type       = "chore"
            scope      = $null
            message    = $firstLine
            isBreaking = $false
        }
    }
}

