            $currentVersion = "1.0.0"
            $commits = @(
                @{ type = "fix"; message = "fix bug" }
                @{ type = "feat"; message = "add feature" }
                @{ type = "feat"; isBreaking = $true; message = "BREAKING: remove old API" }
            )

